def __repr__(self):
    _, format_name = _formats[self.format]
    sparse_cls = 'array' if isinstance(self, sparray) else 'matrix'
    return (
        f"<{format_name} sparse {sparse_cls} of dtype '{self.dtype}'\n"
        f"\twith {self.nnz} stored elements and shape {self.shape}>"
    )

